const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Parse planned_outputs to determine ratios and platforms
  let ratios = ['9:16']; // default
  let platforms = ['meta'];

  if (d.placements) {
    const p = typeof d.placements === 'string' ? JSON.parse(d.placements) : d.placements;
    const ratioSet = new Set();
    const platSet = new Set();

    if (Array.isArray(p)) {
      for (const output of p) {
        if (output.aspect_ratio) ratioSet.add(output.aspect_ratio);
        if (Array.isArray(output.platforms)) {
          for (const plat of output.platforms) platSet.add(plat);
        }
      }
    }

    if (ratioSet.size > 0) ratios = [...ratioSet];
    if (platSet.size > 0) platforms = [...platSet];
  }

  // Determine template_id from template_name
  let template_id = 'multi-item'; // default
  const tn = (d.template_name || '').toLowerCase();
  if (tn.includes('spotlight')) template_id = 'spotlight';
  else if (tn.includes('edu') || tn.includes('education')) template_id = 'educational';
  else if (tn.includes('multi')) template_id = 'multi-item';

  // Parse vehicles (full data from lateral join)
  let vehicles = [];
  if (d.vehicles) {
    vehicles = typeof d.vehicles === 'string' ? JSON.parse(d.vehicles) : d.vehicles;
  }

  results.push({
    json: {
      client_id: d.client_id,
      client: d.client_slug,
      client_name: d.client_name,
      asset_id: d.asset_id,
      template_id: template_id,
      avatar_id: d.avatar_id || null,
      background_id: d.background_id || null,
      ratios: ratios,
      platforms: platforms,
      email: 'system@ad-pilot.ai',
      source: 'weekly_cycle',
      script_text: d.phonetic_script || d.script_text || null,
      display_script: d.script_text || null,
      skip_to_render: true,
      vehicles: vehicles,
      music_id: d.music_id || null,
      music_url: d.music_url || null
    }
  });
}

return results;

const items = $input.all();
const allData = items[0]?.json?.data || [];
const jobs = allData.map(d => ({ asset_id: d.asset_id, job_id: d.job_id, status: d.status }));

return [{
  json: {
    success: true,
    message: `Triggered video generation for ${jobs.length} assets`,
    jobs: jobs,
    triggered_at: new Date().toISOString()
  }
}];

// Pass through Postgres results, strip debug
const items = $input.all();
return items.map(item => ({ json: item.json }));

